@spec sidecar_reconcile_spec  src=tests/specs/sidecar_reconcile_spec.lua  loc=551  sha=b5afaeb  cases=23
@exercises midiManager (h.mm)
@surface   mm:ccs, mm:subscribe, mm:load
@harness   fakeReaper:bindTake, reaper:seedMidi

# Intent
  Algorithm pin-tests for the load-time sidecar↔cc reconciliation pass folded
  into mm:load. Bucket once by (evType, chan, id) and run four stages:
    1. exact (ppq, val) match    → silent bind (no ccsReconciled event)
    2. same ppq, val differs     → valueRebound
    3. consensus offset          → consensusRebound (≥ 50% of bucket sidecars,
                                   min 2 voters)
    4. per-orphan 0/1/many       → orphaned / guessedRebound / ambiguous
  
  Wiring (signal ordering, metadata merge, ext-data hygiene, post-load idx
  fixup) is covered in mm_cc_reconcile_spec; this spec stays algorithm-only.

# Helpers
  @fn ccAt(mm, i)  @ 17-23
  @fn freshTake()  @ 25-31
  @fn packCc(c)  @ 34-47
      -- Cc-shaped record → REAPER's (chanmsg, msg2, msg3) packing.
  @fn seed(take, reaper, spec)  @ 51-64
      -- Seed ccs + sidecars onto the take. No metadata laid down — algorithm tests
      -- don't need the ext-data side effects.
  @fn load(take)  @ 69-79
      -- Returns (mm, events_by_uuid, events_array). `events_by_uuid` collapses
      -- ccsReconciled entries by uuid for compact assertions; the array preserves
      -- order.
  @fn ccsByLoc(mm)  @ 82-86
      -- All ccs on the loaded mm, by location.

# Cases
  @case 'exact (ppq, val) match → silent bind, no event'  [pure]  @ 93-103
  @case 'pa events bind on pitch (silent)'  [pure]  @ 107-117
  @case 'pb fingerprint match (signed val) binds silently'  [pure]  @ 121-131
  @case 'multiple coincident matches all bind silently'  [pure]  @ 135-155
  @case 'val differs at same ppq → valueRebound + non-silent bind'  [pure]  @ 161-179
  @case 'pb val drift round-trips signed val into oldVal/newVal'  [pure]  @ 183-195
  @case 'two sidecars same partKey, one val-differing cc → first binds, second orphans'  [pure]  @ 199-212
  @case 'two sidecars + two ccs at uniform +20 offset → consensus binds both'  [pure]  @ 218-240
  @case 'consensusRebound payload reports the bound cc's ppq + offset'  [pure]  @ 244-262
  @case 'three uniformly-drifted sidecars in one bucket bind despite cross-pair noise'  [pure]  @ 266-287
  @case 'tied top vote-getters drop through stage 3, fall to stage 4 (ambiguous)'  [pure]  @ 291-314
  @case 'no candidates → orphaned (no bind)'  [pure]  @ 320-337
  @case 'one candidate at drifted ppq → guessedRebound binds at the cc's ppq'  [pure]  @ 341-355
  @case 'two candidates → ambiguous, no bind, candidateppqs reported'  [pure]  @ 359-375
  @case 'pa orphan reports pitch (not cc)'  [pure]  @ 379-389
  @case 'two sidecars, one cc same bucket → first guesses, second orphans'  [pure]  @ 393-409
  @case 'mismatched chan: separate buckets → orphaned + unbound cc'  [pure]  @ 415-426
  @case 'mismatched evType: separate buckets (cc vs pb)'  [pure]  @ 430-441
  @case 'mismatched cc#: separate buckets'  [pure]  @ 445-455
  @case 'cc with no sidecars stays plain, no event'  [pure]  @ 459-469
  @case 'separate (chan, cc#) buckets resolve independently'  [pure]  @ 473-494
  @case 'cross-evType events live in different buckets — stage 4 each'  [pure]  @ 498-516
  @case 'mixed: silent + valueRebound + consensus + orphan in one load'  [pure]  @ 522-549

